INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000002', 'citizenship', 'Citizenship language (DELE + CCSE)', 'Язык для гражданства (DELE + CCSE)', 'Naturalization typically requires 10 years legal residence (general rule). DELE A2 and CCSE constitutional knowledge test are standard.', 'Натурализация — как правило 10 лет легального проживания. Нужны DELE A2 и тест CCSE по конституции.', 'https://sede.mjusticia.gob.es/', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000002', 'exam', 'DELE A2 structure', 'Структура DELE A2', 'DELE assesses Spanish at A2 (reading, writing, listening, speaking). Plan 4–8 months from zero for Russian speakers.', 'DELE проверяет испанский на A2. С нуля закладывайте 4–8 месяцев подготовки.', 'https://examenes.cervantes.es/', '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000002', 'timeline', 'Residence → citizenship', 'ВНЖ → гражданство', 'Typical: visa/TIE → renewals → 10 years residence → DELE/CCSE → nationality (12–24 months processing). Sephardic and Latin American exceptions exist.', 'Типично: виза/TIE → продления → 10 лет → DELE/CCSE → гражданство (12–24 мес.). Есть исключения (сефарды, LATAM).', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000002', 'practical', 'NIE and empadronamiento', 'NIE и empadronamiento', 'Foreigners need NIE for tax/bank. Empadronamiento (municipal registration) is required for many procedures.', 'Иностранцам нужен NIE для налогов и банка. Empadronamiento (регистрация по месту жительства) нужна для многих процедур.', NULL, '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000002', 'practical', 'Golden visa reform', 'Реформа golden visa', 'Real-estate investment route largely closed since April 2024. Remaining capital routes are narrow — verify current BOE before planning.', 'Маршрут через недвижимость закрыт с апреля 2024. Оставшиеся инвестиционные варианты узкие — проверяйте актуальный BOE.', 'https://www.boe.es/', '2026-06-01', 5)
