INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000003', 'citizenship', 'Naturalization language (DELF B1)', 'Язык для натурализации (DELF B1)', 'Standard naturalization requires 5 years legal residence and French level B1 (DELF/DALF or equivalent).', 'Стандартная натурализация — 5 лет легального проживания и французский B1 (DELF/DALF или эквивалент).', 'https://www.service-public.fr/particuliers/vosdroits/F2728', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000003', 'exam', 'DELF B1 structure', 'Структура DELF B1', 'DELF B1 tests comprehension, writing, speaking. Plan 6–12 months from zero for Russian speakers.', 'DELF B1 проверяет понимание, письмо, говорение. С нуля закладывайте 6–12 месяцев.', 'https://www.france-education-international.fr/delf-dalf', '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000003', 'timeline', 'Residence → citizenship', 'ВНЖ → гражданство', 'Typical: VLS-TS → renewals → 5 years → B1 → naturalization dossier (12–18 months processing).', 'Типично: VLS-TS → продления → 5 лет → B1 → досье натурализации (12–18 мес.).', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000003', 'practical', 'Prefecture appointments', 'Запись в префектуру', 'After arrival, validate VLS-TS and renew at your department prefecture. Wait times vary by department.', 'После приезда валидируйте VLS-TS и продлевайте в префектуре департамента. Сроки записи различаются.', 'https://www.service-public.fr/', '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000003', 'practical', 'OFII medical visit', 'Медосмотр OFII', 'First long-stay holders must complete OFII registration and medical visit within 3 months of arrival.', 'Держатели первого долгосрочного ВНЖ должны пройти регистрацию OFII и медосмотр в течение 3 месяцев.', 'https://www.ofii.fr/', '2026-06-01', 5)
