INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000004', 'citizenship', 'Citizenship language (B1)', 'Язык для гражданства (B1)', 'Naturalization generally requires 10 years legal residence and Italian B1 (CELI/CILS/PLIDA or equivalent).', 'Натурализация — как правило 10 лет легального проживания и итальянский B1 (CELI/CILS/PLIDA).', 'https://www.interno.gov.it/', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000004', 'exam', 'CELI B1 structure', 'Структура CELI B1', 'CELI B1 assesses reading, writing, listening, speaking. Plan 6–10 months from zero.', 'CELI B1 проверяет чтение, письмо, аудирование, говорение. С нуля — 6–10 месяцев.', 'https://www.cvcl.it/en/celi', '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000004', 'timeline', 'Residence → citizenship', 'ВНЖ → гражданство', 'Typical: visa → permesso renewals → 10 years → B1 → citizenship application (24–36 months processing).', 'Типично: виза → продления permesso → 10 лет → B1 → гражданство (24–36 мес.).', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000004', 'practical', 'Codice fiscale & anagrafe', 'Codice fiscale и anagrafe', 'Tax code (codice fiscale) and municipal registration (anagrafe) are required early for banking and permits.', 'Налоговый код (codice fiscale) и регистрация в comune (anagrafe) нужны для банка и permesso.', NULL, '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000004', 'practical', 'Questura appointments', 'Запись в Questura', 'Permesso di soggiorno is issued by local Questura. Appointment availability varies by city.', 'Permesso выдаёт Questura. Сроки записи зависят от города.', 'https://www.poliziadistato.it/', '2026-06-01', 5)
