INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000005', 'citizenship', 'Naturalization (B1 + 5 years)', 'Натурализация (B1 + 5 лет)', 'Standard naturalization: 5 years legal residence, B1 German, livelihood, clean record. Reforms may shorten to 3–5 years — verify current StAG.', 'Стандарт: 5 лет легального проживания, B1, средства к существованию. Реформы могут сократить срок — проверяйте StAG.', 'https://www.bmi.bund.de/', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000005', 'exam', 'Goethe B1 / telc B1', 'Goethe B1 / telc B1', 'B1 certificate from Goethe-Institut, telc, or ÖSD is standard for naturalization and some permits.', 'Сертификат B1 (Goethe, telc, ÖSD) — стандарт для натурализации и части ВНЖ.', 'https://www.goethe.de/', '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000005', 'timeline', 'Blue Card → permanent residence', 'Blue Card → ПМЖ', 'Blue Card holders may qualify for Niederlassungserlaubnis after 21–33 months depending on language and pension contributions.', 'Держатели Blue Card могут получить Niederlassungserlaubnis через 21–33 мес. при условии языка и взносов.', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000005', 'practical', 'Anmeldung & health insurance', 'Anmeldung и страховка', 'Register address (Anmeldung) within 2 weeks. Statutory or private health insurance is mandatory.', 'Регистрация адреса (Anmeldung) в течение 2 недель. Обязательна государственная или частная страховка.', NULL, '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000005', 'practical', 'Ausländerbehörde wait times', 'Очереди Ausländerbehörde', 'Local immigration offices have long queues in major cities — book appointments early.', 'В крупных городах длинные очереди в Ausländerbehörde — записывайтесь заранее.', 'https://www.make-it-in-germany.com/', '2026-06-01', 5)
