INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000006', 'citizenship', 'Naturalization (5 years + inburgering)', 'Натурализация (5 лет + inburgering)', 'Naturalization after 5 years legal residence, civic integration (inburgering), and sufficient income.', 'Натурализация после 5 лет легального проживания, inburgering и достаточного дохода.', 'https://ind.nl/en/dutch-citizenship', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000006', 'exam', 'Inburgering A2/B1', 'Inburgering A2/B1', 'Civic integration exam includes language (A2 rising to B1) and knowledge of Dutch society (KNM).', 'Экзамен inburgering включает язык (A2→B1) и знание общества (KNM).', 'https://www.inburgeren.nl/', '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000006', 'timeline', 'HSM → permanent residence', 'HSM → ПМЖ', 'Highly skilled migrants may apply for permanent residence after 5 years of legal stay.', 'Highly skilled migrant может подать на ПМЖ после 5 лет легального проживания.', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000006', 'practical', 'BSN registration', 'Регистрация BSN', 'Register at municipality for BSN (citizen service number) — required for work, tax, and healthcare.', 'Регистрация в gemeente для BSN — нужна для работы, налогов и healthcare.', NULL, '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000006', 'practical', '30% ruling (tax)', '30% ruling (налог)', 'Eligible HSMs may qualify for 30% tax-free allowance — verify current Belastingdienst rules.', 'Часть HSM может получить 30% ruling — проверяйте правила Belastingdienst.', 'https://www.belastingdienst.nl/', '2026-06-01', 5)
