INSERT INTO emigro_corridor_digest_items (corridor_id, category, title_en, title_ru, body_en, body_ru, source_url, last_verified, sort_order) VALUES
  ('a0000000-0000-4000-8000-000000000007', 'citizenship', 'Nordic citizenship timelines', 'Сроки гражданства в Nordics', 'Sweden: ~5 years habitual residence. Denmark: 9 years (with exceptions). Norway: 7 years. Finland: 5 years. Language tests apply.', 'Швеция: ~5 лет. Дания: 9 лет. Норвегия: 7 лет. Финляндия: 5 лет. Нужны языковые экзамены.', 'https://www.migrationsverket.se/', '2026-06-01', 1),
  ('a0000000-0000-4000-8000-000000000007', 'exam', 'Swedish / Danish language', 'Шведский / датский язык', 'Citizenship requires language proof: Swedish (SFI → higher) or Danish (Prøve i Dansk 3 / PD3).', 'Для гражданства нужен язык: шведский (SFI и выше) или датский (PD3).', NULL, '2026-06-01', 2),
  ('a0000000-0000-4000-8000-000000000007', 'timeline', 'Work permit → permanent residence', 'Work permit → ПМЖ', 'Sweden: permanent after 4 years work permit. Denmark: dependent on scheme. Processing backlogs vary.', 'Швеция: ПМЖ после 4 лет work permit. Дания — зависит от схемы. Очереди различаются.', NULL, '2026-06-01', 3),
  ('a0000000-0000-4000-8000-000000000007', 'practical', 'Personnummer / CPR', 'Personnummer / CPR', 'Sweden personnummer and Denmark CPR number are essential for banking, tax, and healthcare.', 'Personnummer (SE) и CPR (DK) нужны для банка, налогов и healthcare.', NULL, '2026-06-01', 4),
  ('a0000000-0000-4000-8000-000000000007', 'practical', 'Collective agreements (Sweden)', 'Коллективные договоры (Швеция)', 'Swedish work permits require terms at least as good as collective agreement or industry practice.', 'Шведский work permit требует условий не хуже коллективного договора или отраслевой практики.', 'https://www.migrationsverket.se/', '2026-06-01', 5)
